24→// Loading bar state
25→export function useLoadingBar() {
26→  const [progress, setProgress] = useState(0);
27→  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
28→  const startRef = useRef<() => void>(null);
29→
30→  const stop = useCallback(() => {
31→    if (intervalRef.current) {
32→      clearInterval(intervalRef.current);
33→      intervalRef.current = null;
34→    }
35→  }, []);
36→
37→  const start = useCallback(() => {
38→    setProgress(0);
39→    if (intervalRef.current) clearInterval(intervalRef.current);
40→    intervalRef.current = setInterval(() => {
41→      setProgress(prev => {
42→        const next = prev + Math.random() * 8 + 2;
43→        if (next >= 100) {
44→          clearInterval(intervalRef.current!);
45→          intervalRef.current = null;
46→          setTimeout(() => {
47→            setProgress(0);
48→            setTimeout(() => startRef.current?.(), 100);
49→          }, 1500);
50→          return 100;
51→        }
52→        return next;
53→      });
54→    }, 400);
55→  }, []);
56→
57→  startRef.current = start;
58→
59→  return { progress, start, stop };
60→}
